import{_ as a,o,c as l,a4 as d}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"슬라이드 책장","description":"","frontmatter":{},"headers":[],"relativePath":"10-slide-bookshelf.md","filePath":"10-slide-bookshelf.md"}'),i={name:"10-slide-bookshelf.md"};function r(t,e,s,c,n,h){return o(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="슬라이드-책장" tabindex="-1">슬라이드 책장 <a class="header-anchor" href="#슬라이드-책장" aria-label="Permalink to “슬라이드 책장”">​</a></h1><p><em>슬라이드북 보기</em></p><p>슬라이드 책장은 <code>.ebslide</code> 슬라이드북을 한 장씩 넘겨 보는 전용 공간입니다. (베타) 일반 문서 리더와 달리, 발표 자료처럼 한 화면씩 넘겨 보는 데 맞춰져 있습니다.</p><h2 id="슬라이드북-가져오기" tabindex="-1">슬라이드북 가져오기 <a class="header-anchor" href="#슬라이드북-가져오기" aria-label="Permalink to “슬라이드북 가져오기”">​</a></h2><p><code>.ebslide</code> 파일을 ebookflowy로 공유하거나 열면, 일반 보관함 문서가 아니라 슬라이드 책장의 슬라이드북으로 등록됩니다. 즉 <code>Ebook 책장</code>이 아니라 슬라이드 책장에서 찾게 됩니다.</p><h2 id="보기" tabindex="-1">보기 <a class="header-anchor" href="#보기" aria-label="Permalink to “보기”">​</a></h2><p>하단 <code>슬라이드 책장</code> 탭에서 슬라이드북을 열고 이전·다음으로 넘기며 봅니다. 슬라이드 단위로 이동하므로 발표 자료나 카드형 콘텐츠를 보기에 좋습니다.</p><h2 id="보관-한도" tabindex="-1">보관 한도 <a class="header-anchor" href="#보관-한도" aria-label="Permalink to “보관 한도”">​</a></h2><p>무료 사용자는 슬라이드북을 최대 5개까지 보관할 수 있습니다.</p><ul><li>한도에 도달한 상태에서 새 <code>.ebslide</code>를 가져오면 안내가 표시됩니다.</li><li>기존 슬라이드북을 정리하면 다시 가져올 수 있습니다.</li><li>프리미엄에서는 한도가 완화됩니다(자세한 정책은 설정의 광고/프리미엄 항목 참고).</li></ul><blockquote><p>슬라이드 책장은 베타 기능입니다. 동작과 UI는 업데이트로 바뀔 수 있습니다.</p></blockquote>',11)])])}const b=a(i,[["render",r]]);export{_ as __pageData,b as default};
